-- ════════════════════════════════════════════════════════════════
-- Catálogo de alimentos SMAE 5ª ed (2,870) — Fase 4 (base de datos)
-- Solo tablas de CATÁLOGO (foods + food_measures). Las de registro/perfil/
-- platillos NO se crean aquí: se decidió deprecarlas y extender las de HSC.
-- Datos limpiados (filas rotas descartadas, valores no numéricos → NULL).
-- ════════════════════════════════════════════════════════════════

create table if not exists public.foods (
  id text primary key, grupo text not null, alimento text not null,
  cantidad numeric, unidad text, peso_bruto_g numeric, peso_neto_g numeric,
  kcal numeric, prot_g numeric, lip_g numeric, hc_g numeric, agsat_g numeric,
  agmono_g numeric, agpoli_g numeric, colest_mg numeric, azucar_g numeric,
  fibra_g numeric, vita_ug numeric, ac_ascorbico_mg numeric, ac_folico_ug numeric,
  calcio_mg numeric, hierro_mg numeric, potasio_mg numeric, sodio_mg numeric,
  fosforo_mg numeric, etanol_g numeric, ig text, cg text
);

alter table public.foods
  add column if not exists kcal_100g numeric generated always as (case when peso_neto_g > 0 then round(kcal/peso_neto_g*100,1) end) stored,
  add column if not exists prot_100g numeric generated always as (case when peso_neto_g > 0 then round(prot_g/peso_neto_g*100,1) end) stored,
  add column if not exists lip_100g  numeric generated always as (case when peso_neto_g > 0 then round(lip_g/peso_neto_g*100,1) end) stored,
  add column if not exists hc_100g   numeric generated always as (case when peso_neto_g > 0 then round(hc_g/peso_neto_g*100,1) end) stored,
  add column if not exists fibra_100g numeric generated always as (case when peso_neto_g > 0 then round(fibra_g/peso_neto_g*100,1) end) stored;

create index if not exists foods_search_idx on public.foods using gin (to_tsvector('spanish', alimento));
create index if not exists foods_grupo_idx  on public.foods (grupo);

create table if not exists public.food_measures (
  food_id text primary key references public.foods(id) on delete cascade,
  medida_nombre text, porcion_default numeric, gramos_por_medida numeric
);

alter table public.foods enable row level security;
alter table public.food_measures enable row level security;
drop policy if exists foods_read on public.foods;
drop policy if exists measures_read on public.food_measures;
create policy foods_read    on public.foods         for select using (true);
create policy measures_read on public.food_measures for select using (true);

-- Idempotente: recarga limpia del catálogo.
delete from public.food_measures;
delete from public.foods;

